# Function to generate a random string
function New-RandomString {
    param(
        [int]$Length = 12
    )
    #Characters to use for generating the random string
    # TODO: Allow selection of allowed characters and symbols for random string generation.
    # TODO: Find a better way to set allowed characters for random string generation
    $characters = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789!@#$%^&*()_+=-`~[]\{}|;':"",./<>?"
    $randomString = ""
    for ($i = 0; $i -lt $Length; $i++) {
        $randomIndex = Get-Random -Minimum 0 -Maximum ($characters.Length - 1)
        $randomString += $characters[$randomIndex]
    }
    return $randomString
}

