# Array to store the last 5 outputs
$outputHistory = @("","","","","")

# Button click event handler
$generateButton.Add_Click({
    try {
        $length = [int]$lengthComboBox.SelectedItem # Default to dropdown value

        # Check if the textbox value is a valid integer and override
        if ($numberTextBox.Text -match '^\d+$') {
            $length = [int]$numberTextBox.Text
        } else {
            #If text box is not a number, and has text, do nothing.
            if ($numberTextBox.Text -ne ""){
                #Keep the textbox value as it is.
            }
            else {
                #Textbox is empty, set it to the combobox value.
                $numberTextBox.text = $lengthComboBox.SelectedItem
            }
        }

        $lengthVariableLabel.Text = "Length: " + $length

        # Validate $length before using it
        if (-not ($length -is [int]) -or $length -le 0) {
            $resultLabel.Text = "Please enter a valid positive integer for length."
            return
        }

        $randomString = New-RandomString -Length $length
        $resultLabel.Text = $randomString

        # Store the generated string in an array for history
        #copy to clipboard
        #[System.Windows.Forms.Clipboard]::SetText($randomString)

        # Update output history
        $outputHistory[4] = $outputHistory[3]
        $outputHistory[3] = $outputHistory[2]
        $outputHistory[2] = $outputHistory[1]
        $outputHistory[1] = $outputHistory[0]
        $outputHistory[0] = $randomString

        # Update history length labels
        $HistorylengthLabel1.Text = $outputHistory[0].Length
        $HistorylengthLabel2.Text = $outputHistory[1].Length
        $HistorylengthLabel3.Text = $outputHistory[2].Length
        $HistorylengthLabel4.Text = $outputHistory[3].Length
        $HistorylengthLabel5.Text = $outputHistory[4].Length

        # Display output history
        $output1 = "1. " + $outputHistory[0]
        $lastOutput1.Text = $output1.Substring(0, [Math]::Min(44, $output1.Length))
        $output2 = "2. " + $outputHistory[1]
        $lastOutput2.Text = $output2.Substring(0, [Math]::Min(44, $output2.Length))
        $output3 = "3. " + $outputHistory[2]
        $lastOutput3.Text = $output3.Substring(0, [Math]::Min(44, $output3.Length))
        $output4 = "4. " + $outputHistory[3]
        $lastOutput4.Text = $output4.Substring(0, [Math]::Min(44, $output4.Length))
        $output5 = "5. " + $outputHistory[4]
        $lastOutput5.Text = $output5.Substring(0, [Math]::Min(44, $output5.Length))

    } catch {
        $resultLabel.Text = "An error occurred."
    }
})

